from solution import extract_fields


def test_extract_fields_handles_dicts_lists_and_defaults():
    record = {
        "user": {"id": "u1", "profile": {"name": "Ada"}},
        "orders": [{"total": 30}, {"total": 40}],
    }
    paths = {
        "user_id": "user.id",
        "name": "user.profile.name",
        "first_total": "orders.0.total",
        "missing": "orders.3.total",
    }
    assert extract_fields(record, paths, default="NA") == {
        "user_id": "u1",
        "name": "Ada",
        "first_total": 30,
        "missing": "NA",
    }
